// Grab the sheetId from the previous Create sheet node
const sheetId = $('Create sheet').first().json.sheetId;

// Build the full request body
const body = {
  requests: [
    {
      setDataValidation: {
        range: {
          sheetId: sheetId,
          startRowIndex: 1,
          endRowIndex: 500,
          startColumnIndex: 7,
          endColumnIndex: 100
        },
        rule: {
          condition: {
            type: "ONE_OF_LIST",
            values: [
              { userEnteredValue: "Requested" },
              { userEnteredValue: "Auth Approved" },
              { userEnteredValue: "MR Requested / Appealed" },
              { userEnteredValue: "Final" },
              { userEnteredValue: "Denied" }
            ]
          },
          strict: true,
          showCustomUi: true
        }
      }
    }
  ]
};

return [{ json: body }];

// ── 1. Parse CPT codes ─────────────────────────────────────────
const agentOutput = $('CPT Codes - SFLMED').first().json.output;
let cptCodes = [];
try {
  cptCodes = JSON.parse(agentOutput);
} catch {
  cptCodes = agentOutput.match(/\d{5}/g) || [];
}

// ── 2. Get webhook data - handle all possible body structures ──
const raw = $('Webhook2').first().json;
const body = raw?.body?.body || raw?.body?.[0]?.body || raw?.body || raw;

// Debug - remove after confirming
console.log('raw keys:', Object.keys(raw));
console.log('body keys:', Object.keys(body));
console.log('full_name:', body.full_name);

const fullName = body.full_name || body.name || body.full_name || 'Unknown';
const contactId = body.contact_id || '';
const procedure = body['CONSENT TO READ:'] || body.proccedure || body.procedure || '';
const dobRaw = body.date_of_birth;
const dob = (dobRaw && dobRaw !== 'null')
  ? (() => {
      const [year, month, day] = dobRaw.split('T')[0].split('-');
      return `${month}/${day}/${year}`;
    })()
  : '';
const phone = body.phone || '';
const dateOfSurgery = body['Requested Date for surgery (Approximate)']
  || body['Date Of Surgery?']
  || body['Which Hospital/ Date Of Surgery']
  || '';
const insurance = body['Insurance Provider Name']
  || body['Primary Insurance']
  || body['Insurance Company:']
  || 'Nil';
const dateOfSubmission = new Date().toLocaleDateString('en-US', {
  month: '2-digit', day: '2-digit', year: 'numeric'
});
const sheetTitle = `${fullName} ${contactId}`.trim();

// ── 3. Get sheetId - handle both test and production structures
const sheetData = $('Create sheet3').first().json;
const sheetId = Number(sheetData.properties?.sheetId ?? sheetData.sheetId ?? 0);

// ── 4. Build headers and data row ──────────────────────────────
const fixedHeaders = [
  'Name', 'Date of Birth', 'Date of Surgery', 'Consent To Read',
  'Date of Submission', 'Insurance', 'Member ID', 'Auth NO'
];
const cptHeaders = cptCodes.map(c => `CPT ${c} Status`);
const allHeaders = [...fixedHeaders, ...cptHeaders];

const dataRow = [
  fullName, dob, dateOfSurgery, procedure,
  dateOfSubmission, insurance, contactId, 'Nil',
  ...cptCodes.map(() => 'New')
];

// ── 5. Build batchUpdate requests ──────────────────────────────
const spreadsheetId = '1NX8UOVi4MZjm0nEk0Aq1k6wSFVmylSej-Pwg2n94tPw';
const toCell = val => ({ userEnteredValue: { stringValue: String(val ?? '') } });

const requests = [
  {
    updateCells: {
      rows: [{ values: allHeaders.map(toCell) }],
      fields: 'userEnteredValue',
      start: { sheetId, rowIndex: 0, columnIndex: 0 }
    }
  },
  {
    updateCells: {
      rows: [{ values: dataRow.map(toCell) }],
      fields: 'userEnteredValue',
      start: { sheetId, rowIndex: 1, columnIndex: 0 }
    }
  },
  ...cptCodes.map((code, i) => ({
    setDataValidation: {
      range: {
        sheetId,
        startRowIndex: 1, endRowIndex: 500,
        startColumnIndex: 8 + i, endColumnIndex: 9 + i
      },
      rule: {
        condition: {
          type: 'ONE_OF_LIST',
          values: [
            { userEnteredValue: 'New' },
            { userEnteredValue: 'Authenticated' },
            { userEnteredValue: 'Auth Approved' },
            { userEnteredValue: 'MR Requested / Appealed' },
            { userEnteredValue: 'Final' },
            { userEnteredValue: 'Denied' }
          ]
        },
        strict: true,
        showCustomUi: true
      }
    }
  }))
];

return [{
  json: {
    spreadsheetId,
    sheetId,
    sheetTitle,
    fullName,
    contactId,
    procedure,
    dob,
    phone,
    dateOfSurgery,
    insurance,
    dateOfSubmission,
    body: JSON.stringify({ requests })
  }
}];

const sheetTitle = $('Extract Webhook1').first().json.sheetTitle;
const sheetsMeta = $input.first().json.sheets || [];

const matchingSheet = sheetsMeta.find(s => s.properties.title === sheetTitle);

return [{
  json: {
    sheetExists: !!matchingSheet,
    sheetId: matchingSheet ? matchingSheet.properties.sheetId : null,
    sheetTitle
  }
}];

