// ── Pull from whichever branch ran ──────────────────────────────
const sheetInfo = $('Find Matching Sheet').first().json;
let sheetId = sheetInfo.sheetId;

try {
  const addSheetResponse = $('Add Sheet').first().json;
  if (addSheetResponse?.replies?.[0]?.addSheet?.properties?.sheetId !== undefined) {
    sheetId = addSheetResponse.replies[0].addSheet.properties.sheetId;
  }
} catch {
  // Add Sheet branch didn't run — sheetId already set from Find Matching Sheet
}

const webhookData = $('Extract Webhook1').first().json;

let cptCodes = [];
if (webhookData.predefinedCptCodes) {
  cptCodes = webhookData.predefinedCptCodes;
} else {
  const agentOutput = $('CPT Codes - SFLMED1').first().json.output;
  try {
    cptCodes = JSON.parse(agentOutput);
  } catch {
    cptCodes = agentOutput.match(/\d{5}/g) || [];
  }
}

// ── Determine starting row ───────────────────────────────────────
let existingRows = 0;
try {
  const values = $('Get Existing Values').first().json.values || [];
  existingRows = values.length;
} catch {
  existingRows = 0;
}

const headerRowIndex = existingRows;
const dataRowIndex = existingRows + 1;

// ── Build headers and data row ───────────────────────────────────
const fixedHeaders = [
  'Name',
  'Date of Birth',
  'Date of Surgery',
  'Consent To Read',
  'Date of Submission',
  'Insurance',
  'Member ID',
  'Auth No'
];
const cptHeaders = cptCodes.map(c => `CPT ${c} Status`);
const allHeaders = [...fixedHeaders, ...cptHeaders];

const dataRow = [
  webhookData.fullName,
  webhookData.dob,
  webhookData.dateOfSurgery,
  webhookData.procedure,
  webhookData.dateOfSubmission,
  webhookData.insurance,
  webhookData.contactId,
  'Nil',
  ...cptCodes.map(() => 'New')
];

const toCell = val => ({ userEnteredValue: { stringValue: String(val ?? '') } });

const requests = [
  {
    updateCells: {
      rows: [{ values: allHeaders.map(toCell) }],
      fields: 'userEnteredValue',
      start: { sheetId, rowIndex: headerRowIndex, columnIndex: 0 }
    }
  },
  {
    updateCells: {
      rows: [{ values: dataRow.map(toCell) }],
      fields: 'userEnteredValue',
      start: { sheetId, rowIndex: dataRowIndex, columnIndex: 0 }
    }
  },
  ...cptCodes.map((code, i) => ({
    setDataValidation: {
      range: {
        sheetId,
        startRowIndex: dataRowIndex,
        endRowIndex: dataRowIndex + 1,
        startColumnIndex: 8 + i,
        endColumnIndex: 9 + i
      },
      rule: {
        condition: {
          type: 'ONE_OF_LIST',
          values: [
            { userEnteredValue: 'New' },
            { userEnteredValue: 'Authenticated' },
            { userEnteredValue: 'Auth Approved' },
            { userEnteredValue: 'MR Requested / Appealed' },
            { userEnteredValue: 'Final' },
            { userEnteredValue: 'Denied' }
          ]
        },
        strict: true,
        showCustomUi: true
      }
    }
  }))
];

return [{
  json: {
    sheetId,
    body: JSON.stringify({ requests })
  }
}];

// ── Extract Webhook + Build Sheet Title ─────────────────────────
const raw = $('Webhook3').first().json;
const body = raw?.body?.body || raw?.body?.[0]?.body || raw?.body || raw;

const fullName = body.full_name || body.name || 'Unknown';
const contactId = body.contact_id || '';

const dobRaw = body.date_of_birth;
const dob = (dobRaw && dobRaw !== 'null')
  ? (() => {
      const [year, month, day] = dobRaw.split('T')[0].split('-');
      return `${month}/${day}/${year}`;
    })()
  : '';

const procedure = body['CONSENT TO READ:']
  || body.proccedure
  || body.procedure
  || '';

const dateOfSurgery = body['Requested Date for surgery (Approximate)']
  || body['Date Of Surgery?']
  || body['Which Hospital/ Date Of Surgery']
  || '';

const insurance = body['Insurance Provider Name']
  || body['Primary Insurance']
  || body['Insurance Company:']
  || 'Nil';

const dateOfSubmission = new Date().toLocaleDateString('en-US', {
  month: '2-digit', day: '2-digit', year: 'numeric'
});

const sheetTitle = `${fullName} ${contactId}`.trim();

// ── Predefined CPT code sets for exact-match procedures ──────────
const PREDEFINED_CODES = {
  angiogram: [
    '36245', '36246', '36247', '36248', '37184', '37252', '37253', '37254',
    '37255', '37256', '37257', '37258', '37259', '37260', '37261', '37263',
    '37265', '37267', '37269', '37271', '37273', '37275', '37277', '37280',
    '37281', '37282', '37283', '37284', '37285', '37286', '37287', '37288',
    '37289', '37290', '37291', '37292', '37293', '37294', '37295', '75625',
    '75710', '75716', '76937', '99152', '99153'
  ],
  gsv: ['36475', '76937'],
  fistulagram: [
    '36901', '36902', '36903', '36904', '36905', '36906', '36907', '36908',
    '36909', '36215', '75827', '36010'
  ]
};

// ── Check for exact-match keyword in procedure text ──────────────
const procedureLower = procedure.toLowerCase();
let predefinedCptCodes = null;

if (procedureLower.includes('angiogram')) {
  predefinedCptCodes = PREDEFINED_CODES.angiogram;
} else if (procedureLower.includes('gsv')) {
  predefinedCptCodes = PREDEFINED_CODES.gsv;
} else if (procedureLower.includes('fistulagram')) {
  predefinedCptCodes = PREDEFINED_CODES.fistulagram;
}

return [{
  json: {
    fullName, contactId, dob, procedure,
    dateOfSurgery, insurance, dateOfSubmission, sheetTitle,
    predefinedCptCodes,          // null if no match, otherwise an array
    skipAgent: predefinedCptCodes !== null
  }
}];
